 1Рєњimport type { BaseQueryFn, FetchBaseQueryError, QueryReturnValue } from '@reduxjs/toolkit/query';
 2Рєњimport { createApi } from '@reduxjs/toolkit/query/react';
 3Рєњ
 4Рєњimport type { IApiResponse } from '@/utils/request';
 5Рєњimport { fetchData, isApiResponse } from '@/utils/request';
 6Рєњ
 7Рєњexport type IFetchDataBaseQueryReturnValue<T, M = object> = QueryReturnValue<T, FetchBaseQueryError | {
 8Рєњ  status: 'API_ERROR';
 9Рєњ  data: IApiResponse;
10Рєњ  error: string;
11Рєњ}, M>;
12Рєњexport const fetchDataBaseQuery: BaseQueryFn<
13Рєњ  string | (Parameters<typeof fetchData>[0] & Parameters<typeof fetchData>[1]),
14Рєњ  unknown,
15Рєњ  FetchBaseQueryError | {
16Рєњ    status: 'API_ERROR';
17Рєњ    data: IApiResponse;
18Рєњ    error: string;
19Рєњ  }
20Рєњ> = async (args, api) => {
21Рєњ  const fetchDataOptions = typeof args === 'string' ? { url: args } : args;
22Рєњ  try {
23Рєњ    const {
24Рєњ      autoToast, raw, rawResponse, ...fetchOptions
25Рєњ    } = fetchDataOptions;
26Рєњ    const data = await fetchData({
27Рєњ      ...fetchOptions,
28Рєњ      url: `/${fetchDataOptions.url.replace(/^\//, '')}`,
29Рєњ      signal: api.signal,
30Рєњ    }, { raw, autoToast, rawResponse });
31Рєњ    return { data };
32Рєњ  } catch (e) {
33Рєњ    console.error({ e });
34Рєњ    const apiError = e instanceof Error && isApiResponse(e.cause) ? e.cause : undefined;
35Рєњ    if (apiError) {
36Рєњ      return {
37Рєњ        error: {
38Рєњ          status: 'API_ERROR',
39Рєњ          error: `${e}`,
40Рєњ          data: apiError,
41Рєњ        },
42Рєњ      };
43Рєњ    }
44Рєњ    return {
45Рєњ      error: {
46Рєњ        status: 'CUSTOM_ERROR',
47Рєњ        error: `${e}`,
48Рєњ      },
49Рєњ    };
50Рєњ  }

